import os
import modal
from fastapi import Request, HTTPException, Header
from typing import Optional

app = modal.App("rate-limited-api-gateway")

# Define the dict
gateway_dict = modal.Dict.from_name("rate-limited-api-gateway-output", create_if_missing=True)

image = modal.Image.debian_slim().pip_install("fastapi")

@app.cls(
    image=image,
    secrets=[modal.Secret.from_name("rate-limited-api-gateway-secret")]
)
class APIGateway:
    @modal.enter()
    def setup(self):
        self.gateway_api_key = os.environ.get("GATEWAY_API_KEY")
        self.rate_limit_max = int(os.environ.get("RATE_LIMIT_MAX", "100"))

        # Initialize stats
        if "total_requests_processed" not in gateway_dict:
            gateway_dict["total_requests_processed"] = 0
        if "rate_limit_hits" not in gateway_dict:
            gateway_dict["rate_limit_hits"] = 0

        gateway_dict["gateway_status"] = "operational"
        gateway_dict["api_version"] = "v1"

    @modal.web_endpoint(method="POST")
    async def process_request(self, request: Request, x_api_key: Optional[str] = Header(None)):
        if not x_api_key:
            raise HTTPException(status_code=401, detail="Missing API Key")

        total = gateway_dict.get("total_requests_processed", 0)
        gateway_dict["total_requests_processed"] = total + 1

        key_count = gateway_dict.get(f"rate_limit_{x_api_key}", 0)
        if key_count >= self.rate_limit_max:
            hits = gateway_dict.get("rate_limit_hits", 0)
            gateway_dict["rate_limit_hits"] = hits + 1
            raise HTTPException(status_code=429, detail="Rate limit exceeded")

        gateway_dict[f"rate_limit_{x_api_key}"] = key_count + 1

        try:
            body = await request.json()
        except Exception:
            body = {}

        return {"status": "success", "message": "Request processed", "data": body}

@app.local_entrypoint()
def main():
    print("Initializing gateway dictionary values...")
    gateway_dict["total_requests_processed"] = 0
    gateway_dict["rate_limit_hits"] = 0
    gateway_dict["gateway_status"] = "operational"
    gateway_dict["api_version"] = "v1"
    print("Done.")

